int leftSum = MaxSumBST(node->left, maxSum);
int rightSum = MaxSumBST(node->right, maxSum);
int totalSum = node->data + leftSum + rightSum;

if ((node->left == nullptr || (node->left->data < node->data && node->left == node->left->parent->left)) &&
