struct Node {
    int data;
    Node* parent;
    Node* left;
    Node* right;
    Node(int val = 0, Node* p = nullptr) : data(val), parent(p), left(nullptr), right(nullptr) {}
};

// Функция для подсчета максимальной суммы BST в поддереве
int MaxSumBST(Node* node, int& maxSum) {
    if (!node) return 0;

    int leftSum = MaxSumBST(node->left, maxSum);
    int rightSum = MaxSumBST(node->right, maxSum);

    if ((node->left == nullptr || node->left->data < node->data) &&
