        int totalSum = node->data + leftSum + rightSum;
        maxSum = std::max(maxSum, totalSum);
        return totalSum;
    }

    return INT_MIN; // Возвращаем минимально возможное число, если поддерево не BST
}

// Функция для удаления всех узлов дерева и освобождения памяти
void DeleteTree(Node* node) {
    if (node) {
        DeleteTree(node->left);
        DeleteTree(node->right);
        delete node;
    }
}

