struct Node {
    int data;
    Node* parent;
    Node* left;
    Node* right;
    Node(int val = 0, Node* p = nullptr) : data(val), parent(p), left(nullptr), right(nullptr) {}
};

struct StackNode {
    Node* treeNode;
    StackNode* next;
    StackNode(Node* node) : treeNode(node), next(nullptr) {}
};

struct Stack {
    StackNode* head;
    Stack() : head(nullptr) {}

    ~Stack() {
        while (head) {
            pop();
        }
    }

    bool empty() const {
        return head == nullptr;
    }

    void push(Node* node) {
        StackNode* newNode = new StackNode(node);
        newNode->next = head;
        head = newNode;
    }

    Node* top() {
        if (!empty()) {
            return head->treeNode;
        }
        return nullptr;
    }

    void pop() {
        if (!empty()) {
            StackNode* temp = head;
            head = head->next;
            delete temp;
        }
    }
};

