struct StackNode {
  Node* node_of_bst;
  StackNode* next;
  StackNode(Node* root) : node_of_bst(root), next(nullptr) {}
};

struct Stack {
  StackNode* head;

  bool empty() const {
    return head == nullptr;
  }

  void push(Node* root) {
    StackNode* new_node = new StackNode(root);
    new_node->next = head;
    head = new_node;
  }

  Node* top() {
    if (!empty()) {
      return head->node_of_bst;
    }
    return nullptr;
  }

  void pop() {
    if (!empty()) {
      StackNode* temp = head;
      head = head->next;
      delete temp;
    }
  }
};

int SumCount(Node* root, int& ans) {
  if (!root) return 0;

  int leftSum = (root->left) ? SumCount(root->left, ans) : 0;
